const submit = async (e) => {
  e.preventDefault();
  try {
    const res = await api.post("/auth/login", form);

    // ✅ Save JWT
    localStorage.setItem("token", res.data.token);

    setMessage("Login successful");
    onSuccess(form.username, res.data.role);
  } catch (err) {
    setMessage("Login failed");
  }
};
